<script setup lang="ts">
import { ref } from 'vue'; import schematic from '@/assets/led-resistor.svg'; import { calculateLedResistor, type LedResistorResult } from '@/calculators/ledResistor'
const supply=ref('5'); const forward=ref('2'); const currentMa=ref('10'); const count=ref('1'); const result=ref<LedResistorResult|null>(null); const error=ref('')
function calculate():void{error.value='';try{result.value=calculateLedResistor(Number(supply.value),Number(forward.value),Number(currentMa.value)/1000,Number(count.value))}catch(cause){result.value=null;error.value=cause instanceof Error?cause.message:String(cause)}}
function resistance(value:number):string{return value>=1000?`${Number((value/1000).toPrecision(7))} kΩ`:`${Number(value.toPrecision(7))} Ω`}; function power(value:number):string{return value<1?`${Number((value*1000).toPrecision(7))} mW`:`${Number(value.toPrecision(7))} W`}
</script>
<template><section class="led-layout"><div class="panel"><div class="panel-toolbar"><div><h2>LED 串联电阻计算器</h2><p>支持一个或多个串联 LED，并推荐 E24 标准电阻与安全功率</p></div><span class="circuit-type">R = (VS - n × VF) / IF</span></div><div class="led-input-grid"><label><span>供电电压 VS</span><div class="value-with-unit"><input v-model="supply" type="number" min="0" step="any"><span>V</span></div></label><label><span>单颗 LED 正向压降 VF</span><div class="value-with-unit"><input v-model="forward" type="number" min="0" step="any"><span>V</span></div></label><label><span>目标正向电流 IF</span><div class="value-with-unit"><input v-model="currentMa" type="number" min="0" step="any"><span>mA</span></div></label><label><span>串联 LED 数量 n</span><input v-model="count" type="number" min="1" max="100" step="1"></label></div><button class="wide-action" @click="calculate">计算限流电阻</button><p v-if="error" class="error-message">{{ error }}</p><div v-if="result" class="led-results"><div><span>理论电阻</span><strong>{{ resistance(result.resistance) }}</strong></div><div class="recommended"><span>推荐 E24 电阻</span><strong>{{ resistance(result.recommendedResistance) }}</strong></div><div><span>推荐后的实际电流</span><strong>{{ Number((result.actualCurrent*1000).toPrecision(7)) }} mA</strong></div><div><span>电阻实际功耗</span><strong>{{ power(result.resistorPower) }}</strong></div><div><span>推荐电阻功率</span><strong>≥ {{ result.recommendedPowerRating }} W</strong></div><div><span>LED 总功耗</span><strong>{{ power(result.ledPower) }}</strong></div></div><p class="load-note"><strong>选型建议：</strong>推荐电阻向上取标准阻值，使 LED 电流不超过目标值；电阻额定功率按实际功耗至少 2 倍选择。</p></div><aside class="panel led-schematic-panel"><h2>LED 限流原理图</h2><img :src="schematic" alt="LED 与限流电阻串联原理图"><div class="netlist-check"><strong>连接顺序</strong><p>VCC → LED 阳极 → LED 阴极 → 限流电阻 → GND</p><p>多个 LED 串联时，正向压降按数量累加。</p></div></aside></section></template>
